import React from 'react';
import {Affix, Button} from '@king-design/react';
import './index.styl';
import {bind} from '@king-design/react';

interface Props {
    bottom: number
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        bottom: 0
    };

    private node: any;

    @bind
    shouldFix() {
        // when scroll top greater than or equal to 100
        // fix it at 150px from top
        return window.pageYOffset >= 100;
    }

    @bind
    exclude() {
        // when this demo is not in the viewport
        // don't fix it
        const {top} = (this.node as HTMLElement).getBoundingClientRect();
        const viewport = document.documentElement.clientHeight;

        return top > viewport; 
    }

    render() {
        return (
            <div ref={i => this.node = i}>
                <Affix top={150} shouldFix={this.shouldFix}>
                    <Button type="primary">fix at 150px from the top when scroll top 100px</Button>
                </Affix>
                <Affix bottom={this.state.bottom} exclude={this.exclude}>
                    <Button type="primary">fix at the bottom only when this demo is in viewport</Button>
                </Affix>
            </div>
        )
    }
}

