import React from 'react';
import {Anchor, AnchorLink, Button} from '@king-design/react';
import './index.styl';
import {bind, AnchorLinkProps} from '@king-design/react';

interface Props {
    activeAnchor?: string
    logs: string[]
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        activeAnchor: 'section_one',
        logs: [],
    };

    @bind
    handleAnchorClick(e: MouseEvent, link: AnchorLinkProps) {
        const logs = this.state.logs || [];
        this.setState({logs: [...logs, `点击了锚点: title: ${link.title} href: ${link.href}`]});
    }

    @bind
    handleAnchorChange(href: string) {
        const logs = this.state.logs || [];
        this.setState({logs: [...logs, `锚点改变为: ${href}`]})
    }

    render() {
        return (
            <div className="anchor-demo">
                <Anchor 
                    value={this.state.activeAnchor}
                    onChangeValue={activeAnchor => this.setState({activeAnchor})} 
                    vertical={false}
                    container="#scroll-container2"
                    onClick={this.handleAnchorClick}
                    onChange={this.handleAnchorChange}
                >
                    <AnchorLink href="section_one" title="section1" />
                    <AnchorLink href="section_two" title="section2" />
                    <AnchorLink href="section_three" title="section3" />
                </Anchor>
                <div id="scroll-container2" className="scroll-container2">
                    <div id="section_one" className="section section1">
                        <h2>Section1</h2>
                    </div>
                    <div id="section_two" className="section section2">
                        <h2>Section2</h2>
                    </div>
                    <div id="section_three" className="section section3">
                        <h2>Section3</h2>
                    </div>
                </div>
                {this.state.logs.length ?
                    <div className="logs-container">
                        {this.state.logs.map((log, index) => <div key={index}>{log}</div>)}
                    </div> :
                    undefined
                }
            </div>
        )
    }
}

