import React from 'react';
import {Button, Icon} from '@king-design/react';
import './index.styl';

interface Props {
    loading1?: boolean
    loading2?: boolean
    loading3?: boolean
    loading4?: boolean
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        'loading1': false,
        'loading2': false,
        'loading3': false,
        'loading4': false,
    } as Props;

    onClick(name: keyof Props) {
        this.setState({[name]: true});
    }

    render() {
        return (
            <div>
                <Button type="primary" loading>确认</Button>
                <Button icon circle loading><i className="k-icon k-icon-search"></i></Button>
                <br /> <br />
                <Button type="primary" 
                    loading={this.state.loading1}
                    onClick={this.onClick.bind(this, 'loading1')}
                >点击加载</Button>
                <Button type="primary" 
                    loading={this.state.loading2}
                    onClick={this.onClick.bind(this, 'loading2')}
                ><Icon className="k-icon-search" />点击加载</Button>
                <Button icon circle
                    loading={this.state.loading3}
                    onClick={this.onClick.bind(this, 'loading3')}
                ><Icon className="k-icon-search" /></Button>
                <Button type="primary" 
                    loading={this.state.loading4}
                    onClick={this.onClick.bind(this, 'loading4')}
                >图标在右侧<Icon className="k-icon-search" /></Button>
            </div>
        )
    }
}

