import React from 'react';
import {Checkbox} from '@king-design/react';
import './index.styl';
import {bind} from '@king-design/react';

interface Props {
    languages?: string[]
    options: string[]
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        // 必须初始化为数组
        languages: [],
        options: ['Javascript', 'C++', 'PHP'],
    } as Props;

    @bind
    toggleSelectAll(checked?: boolean) {
        if (checked) {
            this.setState({languages: ['Javascript', 'C++', 'PHP']});
        } else {
            this.setState({languages: []});
        }
    }

    getLength() {
        return this.state.languages!.length;
    }

    render() {
        return (
            <div>
                <Checkbox indeterminate={this.getLength() > 0 && this.getLength() < 3}
                    value={this.getLength() === 3}
                    onChangeValue={this.toggleSelectAll}
                >全选</Checkbox>
                <hr />
                {this.state.options.map(($value, $key) => {
                    return (
                        <Checkbox
                            name="languages" 
                            trueValue={$value}
                            value={this.state.languages}
                            onChangeValue={languages => this.setState({languages})}
                        >{$value}</Checkbox>
                    )
                })}
                Your selected: {JSON.stringify(this.state.languages)}
            </div>
        )
    }
}

