    selectable: boolean
    movable: boolean
    connectable: boolean
    resizable: boolean
    rotable: boolean
    editable: boolean
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        states: {
            selectable: false,
            movable: false,
            connectable: false,
            resizable: false,
            rotatable: false,
            editable: false,
        },
        selectedStates: [],
    };

    componentDidMount() {
        this.on('$change:selectedStates', (v) => {
            const states = {} as States;
            for (let key in this.state.states) {
                states[key as keyof States] = v.indexOf(key as keyof States) > -1;
            }
            this.setState({states: states});
        });
    }

    render() {
