    private form: any;

    set<K extends keyof Props>(key: K, value: Props[K]) {
        this.setState({[key]: value} as Pick<Props, K>);
    }

    private timer: number | undefined;

    @bind
    async ok() {
        // validate the form firstly
        const valid = await this.form.validate();
        if (valid) {
            // make the ok button show loading
            this.dialog.showLoading(); 
            // mock api
            new Promise<void>((resolve, reject) => {
                this.timer = window.setTimeout(() => {
                    if (Math.random() > 0.5) {
                        resolve();
                    } else {
                        reject();
                    }
                }, 2000);
            }).then(() => {
                // if success, close dialog 
                this.dialog.hideLoading();
                this.dialog.close();
            }, () => {
                // if error, don't close dialog
                this.dialog.hideLoading();
                Message.error('error occured');
            });
        }
    }

    beforeUnmount() {
        window.clearTimeout(this.timer);
    }

    render() {
        return (
            <div>
                <Button type="primary"
                    onClick={this.set.bind(this, 'show', true)}
                >Close Dialog Asynchronously</Button>
                <Dialog value={this.state.show} onChangeValue={show => this.setState({show})} title="Customized ok callback"
                    ref={i => this.dialog = i}
                    ok={this.ok}
                >
                    <Form ref={i => this.form = i}>
                        <FormItem value={this.state.code} rules={{required: true, digits: true}} label="Code:">
                            <Input placeholder="please enter digits" value={this.state.code} onChangeValue={code => this.setState({code})} />
                        </FormItem>
                    </Form>
                </Dialog>
            </div>
        )
    }
}

