import React from 'react';
import {
    Form, FormItem,
    Input,
    Select, Option,
    Checkbox,
    Radio,
    ButtonGroup, Button,
    Switch,
    Slider,
    Datepicker,
} from '@king-design/react';
import './index.styl';
import {Message, bind} from '@king-design/react';

interface Props {
    model: Model
}

type Model = {
    input?: string
    select?: string
