    radio?: string
    buttonGroup?: string
    switch?: boolean
    slider?: number
    date?: string
    textarea?: string
    password?: string
    confirmPassword?: string
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        model: {
            checkbox: []
        }
    } as Props;

    private form: any;

    onChangeModel(key: string, value: any) {
        this.setState({
            model: {
                ...this.state.model,
                [key]: value
            }
        })
    }

    @bind
    submit() {
        Message.success('验证通过，开始提交');
        console.log(this.state.model);
    }

    @bind
    async handleSubmit() {
        if (await this.form.validate()) {
            console.log('验证通过，开始提交');
        } else {
            // 验证失败，我们可以获取第一条出错的FormItem
            console.log(this.form.getFirstInvalidFormItem());
        }
    }

    @bind
    reset() {
        this.setState({model: {checkbox: []}});
        this.form.reset();
        console.log(this.state.model);
    }

    render() {
