                >
                    <Checkbox trueValue="Javascript" value={this.state.model.checkbox} onChangeValue={this.onChangeModel.bind(this, 'checkbox')}>Javascript</Checkbox>
                    <Checkbox trueValue="PHP" value={this.state.model.checkbox} onChangeValue={this.onChangeModel.bind(this, 'checkbox')}>PHP</Checkbox>
                    <Checkbox trueValue="C++" value={this.state.model.checkbox} onChangeValue={this.onChangeModel.bind(this, 'checkbox')}>C++</Checkbox>
                </FormItem>
                <FormItem label="Radio" value={this.state.model.radio}
                    rules={{required: true}} 
                    messages={{required: '必须选择'}}
                >
                    <Radio trueValue="Javascript" value={this.state.model.radio} onChangeValue={this.onChangeModel.bind(this, 'radio')}>Javascript</Radio>
                    <Radio trueValue="PHP" value={this.state.model.radio} onChangeValue={this.onChangeModel.bind(this, 'radio')}>PHP</Radio>
                    <Radio trueValue="C++" value={this.state.model.radio} onChangeValue={this.onChangeModel.bind(this, 'radio')}>C++</Radio>
                </FormItem>
                <FormItem label="Radio ButtonGroup" value={this.state.model.buttonGroup}
                    rules={{required: true}} 
                    messages={{required: '必须选择'}}
                >
                    <ButtonGroup checkType="radio" value={this.state.model.buttonGroup} onChangeValue={this.onChangeModel.bind(this, 'buttonGroup')}>
                        <Button value="Javascript">Javascript</Button>
                        <Button value="PHP">PHP</Button>
                        <Button value="C++">C++</Button>
                    </ButtonGroup>
                </FormItem>
                <FormItem label="Switch" value={this.state.model.switch}>
                    <Switch value={this.state.model.switch} onChangeValue={this.onChangeModel.bind(this, 'switch')} />
                </FormItem>
                <FormItem value={this.state.model.slider} rules={{required: true, min: 1}} label="Slider">
                    <Slider value={this.state.model.slider} onChangeValue={this.onChangeModel.bind(this, 'slider')} showInput={false} />
                </FormItem>
                <FormItem value={this.state.model.date} rules={{required: true}} label="Datepicker">
                    <Datepicker value={this.state.model.date} onChangeValue={this.onChangeModel.bind(this, 'date')} />  
                </FormItem>
                <FormItem label="Textarea" value={this.state.model.textarea}
                    rules={{required: true}}
                >
                    <Input type="textarea" value={this.state.model.textarea} onChangeValue={this.onChangeModel.bind(this, 'textarea')} />
                </FormItem>
                <FormItem label="Password" value={this.state.model.password}
                    rules={{required: true}}
                >
                    <Input type="password" value={this.state.model.password} onChangeValue={this.onChangeModel.bind(this, 'password')} />
                </FormItem>
                <FormItem label="Confirm Password" value={this.state.model.confirmPassword}
                    rules={{required: true, equal: this.state.model.password}}
                >
                    <Input type="password" value={this.state.model.confirmPassword} onChangeValue={this.onChangeModel.bind(this, 'confirmPassword')} />
                </FormItem>
                <FormItem>
                    <Button type="primary" htmlType="submit" onClick={this.handleSubmit}>提交</Button>
                    <Button style={{"marginLeft":"8px"}} onClick={this.reset}>重置</Button>
                </FormItem>
            </Form>
        )
    }
}

