import React from 'react';
import {Form, FormItem, Input, Button} from '@king-design/react';
import './index.styl';
import {bind} from '@king-design/react';

interface Props {
    descriptions: string[]
}

// 添加全局规则
Form.addMethod('letter', (value, param) => {
    return /^[a-z|A-Z]+$/.test(value);
}, '只能输入字母');

export default class Demo extends React.Component<{}, Props> {
    public state = {
        descriptions: ['', '']
    };

    set<K extends keyof Props>(key: K, value: Props[K]) {
        this.setState({[key]: value} as Pick<Props, K>);
    }

    add() {
        this.setState({descriptions: this.state.descriptions.concat('')});
    }

    @bind
    remove(index: number) {
        const descriptions = this.state.descriptions.slice(0);
        descriptions.splice(index, 1);
        this.setState({descriptions: descriptions});
    }

    @bind
    unique(value: string) {
        let count = 0;
        this.state.descriptions.find(item => {
            if (item === value) count++;
            return count > 1;
        });

        // 直接返回错误文案，或者也可以单独定义messages为{unique: '不能相同'}
        return count === 1 || '不能相同';
    }

    onInput(index: number, v?: string) {
        const descriptions = this.state.descriptions.slice(0);
        descriptions[index] = v!;
        this.setState({descriptions});
    }

    render() {
        return (
            <Form>
                <FormItem label="描述">
                    {this.state.descriptions.map(($value, $key) => {
                        return (
                            <FormItem
                                slotAppend={<Button onClick={this.remove.bind(self, $key)}>删除</Button>}
                                value={$value}
                                hideLabel
                                rules={{
                                    required: true, 
                                    // 自定义全局规则
                                    letter: true,
                                    // 自定义局部规则，所有描述必须不重复
                                    unique: this.unique 
                                }}
                            >
                                <Input value={this.state.descriptions[$key]} 
                                    onChangeValue={this.onInput.bind(this, $key)}
                                />    
                            </FormItem>
                        )
                    })}
                    <Button onClick={this.add}>添加</Button>
                </FormItem>
            </Form>
        )
    }

}

