import React from 'react';
import {Icon, Input, Copy} from '@king-design/react';
import './index.styl';
import {useConfigContext} from '@king-design/react';
interface Props {
    keywords?: string
    fonts: string[][]
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        keywords: '',
        fonts: [
            ["information-fill"],
            ["warning-fill"],
            ["success-fill"],
            ["error-fill"],
            ["question-fill"],
            ["heart-fill"],
            ['heart'],
            ['notification-fill'],
            ['notification'],
            ["information"], 
            ["alert"],
            ["question"],
            ["zoom-in"],
            ["zoom-out"],
            ["close-outline"],
            ["check-outline"],
            ["time"],
            ['right-circled', 'arrow'],
            ['down-circled', 'arrow'],
            ['right-circled', 'arrow'],
            ['up-circled', 'arrow'],
            ['right-squared', 'arrow'],
            ['down-squared', 'arrow'],
            ['left-squared', 'arrow'],
            ['up-squared', 'arrow'],
            ['right', 'arrow'],
            ['down', 'arrow'],
            ['left', 'arrow'],
            ['up', 'arrow'],
            ['right-bold', 'arrow'],
            ['down-bold', 'arrow'],
            ['left-bold', 'arrow'],
            ['up-bold', 'arrow'],
            ['sort'],
            ['sort-bold'],
            ['close'],
            ['close-bold'],
            ['check'],
            ['check-bold'],
            ['add'],
            ['add-bold'],
            ['minus'],
            ['minus-bold'],
            ['share'],
            ['tag'],
            ['clone'],
            ['cloud'],
            ['pin'],
            ['home'],
            ['cut'],
            ['server'],
            ['internet'],
            ['mail'],
            ['paper'],
            ['phone'],
            ['panel'],
            ['alarm'],
            ['earphone'],
            ['settings-horizontal'],
            ['settings-vertical'],
            ['settings'],
            ['message'],
            ['return-right'],
            ['picture'],
            ['logout'],
            ['all'],
            ['drag'],
            ['more'],
            ['more-circled'],
            ['folder'],
            ['folder-open'],
            ['lock'],
            ['unlock'],
            ['user'],
            ['users'],
            ['edit'],
            ['location'],
            ['delete'],
            ['calendar'],
            ['search'],
            ['batchsearch'],
            ['hidden'],
            ['visible'],
            ['refresh'],
            ['upload'],
            ['download'],
            ['start'],
            ['stop'],
            ['sortorder'],
            ["history"],
            ["correlation"],
            ["webui"],
            ["log"],
            ["save"],
            ["memory"],
            ["Physicalport"],
            ["queue"],
            ["channel"],
            ["cpu"],
            ["change"],
            ["subnet"],
            ["listener"],
            ["outboundrules"],
            ["inboundrules"],
            ["fullscreen"],
            ["add-circled"],
            ["think"],
        ],
    } as Props;

    private classNames(classNames: Record<string, any> | string) {
        if (typeof classNames === 'string') return classNames;
        const ret = [];
        for (let key in classNames) {
            const value = classNames[key];
            if (value) {
                ret.push(key);
            }
        }
        return ret.join(' ');
    }

    private config = useConfigContext();

    componentDidMount() {
        const fonts = this.state.fonts;
        const map: Record<string, boolean> = {};
        fonts.forEach(([font]) => {
            if (map[font]) {
                console.log('duplicated', font);
            }
            map[font] = true;
        });
    }

    filter() {
        const keywords = this.state.keywords!.trim().toLowerCase();
        const fonts = this.state.fonts;

        if (!keywords) return fonts;

        return fonts.filter((font) => {
            return `${this.config.k}-icon-${font[0]}`.includes(keywords) ||
                font[1] && font[1].includes(keywords);
        });
    }

    render() {
        return (
            <div>
                <Input value={this.state.keywords} onChangeValue={keywords => this.setState({keywords})} placeholder="Search icon" clearable />
                <div className="icons">
                    {this.filter().map(($value, $key) => {
                        return (
                            <Copy text={this.config.k + '-icon-' + $value[0]}>
                                <div className="icon">
                                    <Icon 
                                        className={this.classNames(this.config.k + '-icon-' + $value[0])}
                                        size="large"
                                    />
                                    <div>{this.config.k + '-icon-' + $value[0]}</div>
                                </div>
                            </Copy>
                        )
                    })}
                </div>
            </div>
        )
    }
}

