import React from 'react';
import {Input} from '@king-design/react';
import './index.styl';
import tinycolor from 'tinycolor2';
import {bind} from '@king-design/react';

interface Props {
    value: string
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        value: '#ddd'
    };

    @bind
    onInput(e: InputEvent) {
        const value = (e.target as HTMLInputElement).value.trim();
        const color = tinycolor(value);
        if (color.isValid()) {
            const newValue = color.toHexString();
            this.setState({value: newValue});
        }
    }

    render() {
        return (
            <div>
                <Input value={this.state.value} onInput={this.onInput} />
                <br />
                <Input frozenOnInput value={this.state.value} onInput={this.onInput} />
            </div>
        )
    }
}

