interface Props {
    color: string
    colors: Color[]
    percent: number
}

type Color = {
    color: string
    percent: number
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        color: '#ff9800',
        colors: [
            {color: '#9CD6FB', percent: 25},
            {color: '#60C2FF', percent: 50},
            {color: '#32ACF7', percent: 75},
            {color: '#0091EA', percent: 100}
        ],
        percent: 25
    };

    @bind
    add() {
        if (this.state.percent >= 100) return;

        this.setState({percent: this.state.percent + 25});
    }

    @bind
    minus() {
        if (this.state.percent <= 0) return;

        this.setState({percent: this.state.percent - 25});
    }

