export default class extends Component {
    static template = template;

    static defaults() {
        return {
            value: 2018
        };
    }

    generateData(value: number) {
        const start = value - 5;
        return Array.apply(null, {length: 10} as unknown[])
            .map((v, i) => {
                const year = start + i; 
                return {
                    label: `${year}年`,
                    value: year
                };
            });
    }

    disable(value: number) {
        // 排除闰年
        return value % 4 === 0 && (value % 100 !== 0 || value % 400 === 0);
    }
}

