import React from 'react';
import {Select, Option} from '@king-design/react';
import {bind} from '@king-design/react';

interface Props {
    users: any[]
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        users: []
    } as Props;

    private lastFetchId = 0;

    @bind
    search(e: Event) {
        const keywords = (e.target as HTMLInputElement).value.trim();

        if (!keywords) return;

        const fetchId = ++this.lastFetchId
        fetch('https://randomuser.me/api/?results=10')
            .then(response => response.json())
            .then(body => {
                if (fetchId !== this.lastFetchId) return;
                this.setState({users: body.results});
            });
    }

    render() {
        return (
            <Select multiple filterable filter={() => true} onInput={this.search}>
                {this.state.users.map(($value, $key) => {
                    return (
                        <Option 
                            value={$value.login.username}
                        >{$value.name.first} {$value.name.last}</Option>
                    )
                })}
            </Select>
        )
    }
}

