import React from 'react';
import {Select, Option, Icon} from '@king-design/react';
import './index.styl';

export default class Demo extends React.Component {
    public state = {type: 'dashed', icons: ['ion-camera'], icons1: []};

    private classNames(classNames: Record<string, any> | string) {
        if (typeof classNames === 'string') return classNames;
        const ret = [];
        for (let key in classNames) {
            const value = classNames[key];
            if (value) {
                ret.push(key);
            }
        }
        return ret.join(' ');
    }

    render() {
        return (
            <div>
                <div className="item">
                    <span className="label">border:</span>
                    <Select value={this.state.type} onChangeValue={type => this.setState({type})}>
                        {['solid', 'dashed', 'dotted'].map(($value, $key) => {
                            return (
                                <Option
                                    value={$value}
                                >
                                    <div style={{borderBottom: `1px ${$value} #666`}} className="line"></div>
                                </Option>
                            )
                        })}
                    </Select>
                    <div style={{border: `1px ${this.state.type} #b2b2b2`}} className="rect">
                        Rectangle
                    </div>
                </div>
                <div className="item">
                    <span className="label">multiple:</span>
                    <Select value={this.state.icons} onChangeValue={icons => this.setState({icons})} multiple
                        slotValue={([value, label]) => {
                            return <>
                                <Icon className={this.classNames(value)} style={{"verticalAlign":"middle"}} />
                                <span className="middle">{value}</span>
                            </>
                        }}
                    >
                        {['ion-chatbubble', 'ion-person-stalker', 'ion-beer', 'ion-camera'].map(($value, $key) => {
                            return (
                                <Option
                                    value={$value}
                                >
                                    <Icon className={this.classNames($value)} />
                                </Option>
                            )
                        })}
                    </Select>
                </div>
                <div className="item">
                    <span className="label">multiple values:</span>
                    <Select value={this.state.icons1} onChangeValue={icons1 => this.setState({icons1})} multiple
                        slotValues={([values, labels]) => {
                            return <>
                                <div className="k-value">已选择{values.length}项 / 总共4项</div>
                            </>
                        }}
                    >
                        {['ion-chatbubble', 'ion-person-stalker', 'ion-beer', 'ion-camera'].map(($value, $key) => {
                            return (
                                <Option
                                    value={$value}
                                >
                                    <Icon className={this.classNames($value)} />
                                </Option>
                            )
                        })}
                    </Select>
                </div>
            </div>
        )
    }
}

