                    <div className="footer">
                        <Button size="small" onClick={this.hide}>取消</Button>
                        <Button type="primary" size="small" onClick={this.confirm}>确定</Button>
                    </div>
                </>}
                className="custom-select"
                ref={i => this.select = i}
            >
            </Select>
        )
    }
}

