import React from 'react';
import {Split, Table, TableColumn, Tabs, Tab, FormItem, Button, Icon} from '@king-design/react';
import './index.styl';
import {range, bind} from '@king-design/react/components/utils';
import {nextTick} from 'intact';

interface Props {
    data: DataItem[]
    tab?: string
    size?: string
    selectedData?: DataItem
    checkedKeys?: number[]
}

type DataItem = {
    name: string
    ip: string
}

const data =  range(0, 10).map(item => {
    return {
        name: 'name ' + item,
        ip: '127.0.0.' + item
    };
});

export default class Demo extends React.Component<{}, Props> {
    public state = {
        data,
        tab: 'detail',
        size: '0px',
        selectedData: undefined,
        checkedKeys: [],
    } as Props;

    private table: any;

    private classNames(classNames: Record<string, any> | string) {
        if (typeof classNames === 'string') return classNames;
        const ret = [];
        for (let key in classNames) {
            const value = classNames[key];
            if (value) {
                ret.push(key);
            }
        }
        return ret.join(' ');
    }

    @bind
    _close() {
        this.setState({size: '0px'});
    }

    _open() {
        if (this.state.size === '0px') {
            this.setState({size: '200px'});
        }
    }

    @bind
    _togglePanel(keys: number[] | undefined) {
        if (keys!.length === 1) {
            // 只选中一行时，展开详情面板
            const data = this.table.getCheckedData()[0];
            this.setState({
                selectedData: data,
                checkedKeys: keys,
            });
            this._open();
        } else {
            this._close();
        }
    }

    @bind
    _onClickRow(data: DataItem, index: number, key: number) {
        let checkedKeys = this.state.checkedKeys!;
        if (checkedKeys.length === 1 && checkedKeys[0] === key) {
            // 如果只选中了一行，再次点击当前行，则取消选中
            checkedKeys = [];
        } else {
            // 否则只选中当前行
            checkedKeys = [key];
        }
        this.setState({checkedKeys}, () => {
            this._togglePanel(checkedKeys);
        });
    }

    render() {
        return (
            <div className="split-container">
                <Split mode="vertical"
                    slotFirst={<>
                        <Table data={this.state.data}
                            fixHeader
                            ref={i => this.table = i}
                            rowCheckable={false}
                            checkedKeys={this.state.checkedKeys}
                            onClickRow={this._onClickRow}
                            onChangeCheckedKeys={this._togglePanel}
                        >
                            <TableColumn title="名称" key="name" />
                            <TableColumn title="网段" key="ip" />
                            <TableColumn title="操作" key="op"
                                slotTemplate={([value, index]) => {
                                    return <>
                                        <a>删除</a> 
                                    </>
                                }}
                            >
                            </TableColumn>
                        </Table>
                    </>}
                    slotLast={<>
                        <Button type="none" icon className="close"
                            onClick={this._close}
                        >
                            <Icon className="ion-ios-close-empty" size="40" />
                        </Button>
                        <Tabs value={this.state.tab} onChangeValue={tab => this.setState({tab})}>
                            <Tab value="detail">详情</Tab>
                            <Tab value="data">流量统计</Tab>
                            <Tab value="tag">标签</Tab>
                        </Tabs>
                        {this.state.tab === 'detail' && this.state.selectedData ?
                            <div className="tab-panel">
                                <FormItem label="创建时间：">2018-09-28 17:31:25</FormItem>
                                <FormItem label="弹性IP：">{this.state.selectedData.ip}</FormItem>
                                <FormItem label="名称：">{this.state.selectedData.name}</FormItem>
                            </div> :
                            undefined
                        }
                    </>}
                    slotDrag={<><Icon className="ion-drag" /></>}
                    lastSize={this.state.size}
                    onChangeLastSize={size => this.setState({size})}
                    className={this.classNames({closed: this.state.size === '0px'})}
                    min={10}
                >
                </Split>
            </div>
        )
    }
}

