    expandedKeys: TableRowKey[]
    data: DataItem[]
}

type DataItem = {
    name: string
    email: string
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        expandedKeys: [],
        data: [
            {name: 'Javey', email: 'jiawei23716@sina.com'}, 
            {name: 'Jiawei', email: 'zoujiawei@gmail.com'}
        ],
    } as Props;

    private __test1: any;

    private __test2: any;

    private classNames(classNames: Record<string, any> | string) {
        if (typeof classNames === 'string') return classNames;
        const ret = [];
        for (let key in classNames) {
            const value = classNames[key];
            if (value) {
                ret.push(key);
            }
        }
        return ret.join(' ');
    }

    @bind
    toggleExpand(data: DataItem, index: number) {
        const expandedKeys = this.state.expandedKeys.slice(0);
        const i = expandedKeys.indexOf(index);
        if (i > -1) {
            expandedKeys.splice(i, 1);
        } else {
            expandedKeys.push(index);
        }
        this.setState({expandedKeys: expandedKeys});
    }

    render() {
        return (
            <Table 
                    data={this.state.data} 
                    checkType="none"
                    rowExpandable={false}
                    expandedKeys={this.state.expandedKeys}
                    ref={i => this.__test2 = i}
                >
                    <b:expand args="[data, index]">
                        <div className="expand">Email: {data.email}</div>
                    </b:expand>
                    <TableColumn title="点击+，展开内容" key="name"
                        slotTemplate={([data, index]) => {
                            return <>
                                <div>
                                    <i 
                                        className={this.classNames({
                                            'icon': true,
                                            'ion-ios-plus-outline': this.state.expandedKeys.indexOf(index) < 0,
                                            'ion-ios-minus-outline': this.state.expandedKeys.indexOf(index) > -1})}
                                        onClick={this.toggleExpand.bind(this, data, index)}
                                    ></i>
                                    <span className="name">{data.name}</span>
                                </div>
                            </>
                        }}
                    >
                    </TableColumn>
                </Table>
            </div>
        )
    }
}

