import React from 'react';
import {Table, TableColumn, Button} from '@king-design/react';
import './index.styl';
import {bind} from '@king-design/react/components/utils';

interface Props {
    data: any[]
    num: number
    isShow: boolean
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        data: [
            {
                a: 'Cell 1-1', 
                b: 'Cell 1-2', 
                c: 'Cell 1-3'
            },
            {
                a: 'Cell 2-1', 
                b: 'Cell 2-2', 
                c: 'Cell 2-3'
            }
        ],
        num: 3,
        isShow: false,
    };

    @bind
    addRow() {
        const num = this.state.num;
        const data = this.state.data.slice();
        data.push({
            a: `Cell ${num}-1`, 
            b: `Cell ${num}-2`, 
            c: `Cell ${num}-3`
        });
        this.setState({
            data,
            num: num + 1
        });
    }

    @bind
    removeRow() {
        const data = this.state.data.slice();
        data.shift();
        this.setState({data});
    }

    @bind
    toggleColumn() {
        this.setState({isShow: !this.state.isShow});
    }

    render() {
        return (
            <div>
                <Button type="primary" onClick={this.addRow}>增加一行</Button>
                <Button type="primary" onClick={this.removeRow}>删除一行</Button>
                <Button type="primary" onClick={this.toggleColumn}>
                    {this.state.isShow ?
                        <React.Fragment>删除</React.Fragment> :
                        <React.Fragment>增加</React.Fragment>
                    }
                    一列
                </Button>
                <Table data={this.state.data} resizable rowKey={row => row.a}>
                    <TableColumn key="a" title="Title 1" />
                    {this.state.isShow ?
                        <TableColumn key="b" title="Title 2"/> :
                        undefined
                    }
                    <TableColumn key="c" title="Title 3" />
                </Table>
                <Table data={this.state.data} resizable rowKey={row => row.a} animation={false}>
                    <TableColumn key="a" title="Title 1" />
                    {this.state.isShow ?
                        <TableColumn key="b" title="Title 2"/> :
                        undefined
                    }
                    <TableColumn key="c" title="Title 3" />
                </Table>
            </div>
        )
    }
}

