    tab?: number
    tabs: TabItem[]
    size: TabsProps['size']
    types: TabsProps['type'][]
}

type TabItem = {
    value: number
    label: string
}

let id = 3;
export default class Demo extends React.Component<{}, Props> {
    public state = {
        tab: 1,
        tabs: [
            {value: 1, label: 'Tab 1'},
            {value: 2, label: 'Tab 2'},
            {value: 3, label: 'Tab 3'},
        ],
        size: 'large',
        types: ['default', 'card', 'flat-card']
    } as Props;

    @bind
    _remove(value: number) {
        const tabs = this.state.tabs.slice(0);
        const index = tabs.findIndex(item => item.value === value);
        tabs.splice(index, 1);

        // 如果删除当前tab，则切换至下一个
        let tab = this.state.tab;
        if (value === tab) {
            const item = tabs[index] || tabs[index - 1];
            tab = item ? item.value : undefined;
        }

        this.setState({tabs, tab});
    }

    @bind
    _add() {
        const tabs = this.state.tabs.slice(0);
