import React from 'react';
import {Tags, Tag, Split, Tooltip} from '@king-design/react';
import {TagProps} from '@king-design/react';

interface Props {
    tags1: Required<TagProps>['type'][]
    tags2: Required<TagProps>['type'][]
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        tags1: ['default', 'primary', 'success', 'warning', 'danger'],
        tags2: ['default', 'primary', 'success', 'warning', 'danger'],
    } as Props;

    remove(name: keyof Props, type: Required<TagProps>['type'], e: MouseEvent) {
        e.preventDefault();

        const tags = this.state[name].filter((tag) => tag !== type);
        this.setState({[name as 'tags1']: tags});
    }

    render() {
        return (
            <Split style={{"width":"600px","background":"#e1e1e1"}}
                slotFirst={<>
                    <Tags>
                        {this.state.tags1.map(($value, $key) => {
                            return (
                                <Tag
                                    key={$value}
                                    type={$value}
                                    closable
                                    onClose={(e) => this.remove('tags1', $value, e)}
                                >{$value}</Tag>
                            )
                        })}
                    </Tags>
                </>}
                slotLast={<>
                    <Tags nowrap>
                        {this.state.tags2.map(($value, $key) => {
                            return (
                                <Tag
                                    key={$value}
                                    type={$value}
                                    closable
                                    onClose={(e) => this.remove('tags2', $value, e)}
                                >{$value}</Tag>
                            )
                        })}
                        <Tooltip content="test" key="test">
                             <Tag>with tooltip</Tag>
                        </Tooltip>
                    </Tags>
                </>}
            >
            </Split>
        )
    }
}

