import React from 'react';
import {Tooltip, ButtonGroup, Button, Form, FormItem, Select, Option, Spinner} from '@king-design/react';
import './index.styl';

interface Props  {
    position: 'left' | 'bottom' | 'right' | 'top' | 'custom'
    xAxisKeywords: string[]
    yAxisKeywords: string[]
    pos: Pos
}
type Pos = { 
    myX: string
    myXOffset: number
    myY: string
    myYOffset: number
    atX: string
    atXOffset: number
    atY: string
    atYOffset: number
}
export default class Demo extends React.Component<{}, Props> {
    public state = {
        position: 'left',
        xAxisKeywords: ['left', 'center', 'right'],
        yAxisKeywords: ['top', 'center', 'bottom'],
        pos: {
            myX: 'center',
            myXOffset: 0,
            myY: 'bottom',
            myYOffset: -10,
            atX: 'center',
            atXOffset: 0,
            atY: 'top',
            atYOffset: 0,
        },
    } as Props;

    onChangePos(key: string, value: any) {
        this.setState({
            pos: {
                ...this.state.pos,
                [key]: value
            }
        })
    }

    getPosition() {
        const position = this.state.position;
        const getNumStr = (num: number) => num > 0 ? `+${num}` : num === 0 ? '' : num;

        if (position === 'custom') {
            const pos = this.state.pos;
            return {
                my: `${pos.myX}${getNumStr(pos.myXOffset)} ${pos.myY}${getNumStr(pos.myYOffset)}`,
                at: `${pos.atX}${getNumStr(pos.atXOffset)} ${pos.atY}${getNumStr(pos.atYOffset)}`,
            };
        }

        return position;
    }

    getContent() {
        return JSON.stringify(this.getPosition());
    }

    render() {
        return (
            <Form>
                <FormItem label="position:">
                    <ButtonGroup checkType="radio" value={this.state.position} onChangeValue={position => this.setState({position})}>
                        {['left', 'right', 'top', 'bottom', 'custom'].map(($value, $key) => {
                            return (
                                <Button 
                                    value={$value}
                                >{$value}</Button>
                            )
                        })}
                    </ButtonGroup>
                </FormItem>
                {this.state.position === 'custom' ?
                    <React.Fragment>
                        <FormItem label="my:">
                            x: <Select width="100" value={this.state.pos.myX} onChangeValue={this.onChangePos.bind(this, 'myX')}>
                                {this.state.xAxisKeywords.map(($value, $key) => {
                                    return (
                                        <Option 
                                            value={$value}
                                        >{$value}</Option>
                                    )
                                })}
                            </Select>
                            <Spinner vertical value={this.state.pos.myXOffset} onChangeValue={this.onChangePos.bind(this, 'myXOffset')} />
                            y: <Select width="100" value={this.state.pos.myY} onChangeValue={this.onChangePos.bind(this, 'myY')}>
                                {this.state.yAxisKeywords.map(($value, $key) => {
                                    return (
                                        <Option 
                                            value={$value}
                                        >{$value}</Option>
                                    )
