        errorMsg: '',
        tourData: [
            {
                target: '#step1',
                title: '第一步',
                content: '这是第一步的引导说明',
                position: 'bottom'
            },
            {
                target: '#step2',
                title: '第二步',
                content: '这是第二步的引导说明',
                position: 'right'
            },
            {
