                title: '第三步',
                content: '请在输入框中输入"next"以继续',
                position: 'bottom'
            },
            {
                target: '#step4',
                title: '最后一步',
                content: '恭喜您完成了所有步骤',
                position: 'top'
            }
        ]
    };

    @bind
    startTour() {
