import {Transfer, Input, Select, Option, Tag} from '@king-design/react';
import './index.styl';
import {bind} from '@king-design/react';

interface Props {
    policy?: string | null
    data: DataItem[]
    keywords?: string
    value?: string[]
}

type DataItem = {
    name: string
    policy: string
    members: number
    desc: string
    disabled?: boolean
}

function mockApi(policy: string) {
    const data: DataItem[] = [
        {name: 'AdministratorAccess', policy: 'system', 'members': 11, desc: '管理所有资源的权限'},
        {name: 'OSSFullAccess', policy: 'common', 'members': 11, desc: '管理所有资源的权限'},
        {name: 'SupportFullAccess', policy: 'common', 'members': 11, desc: '管理所有资源的权限'},
        {name: 'BSSFullSupportAccess', policy: 'common', 'members': 11, desc: '管理所有资源的权限', disabled: true},
        {name: 'SystemFullAccess', policy: 'system', 'members': 11, desc: '管理所有资源的权限'},
        {name: 'CommonAccess', policy: 'common', 'members': 11, desc: '管理所有资源的权限'},
    ];

    return new Promise<DataItem[]>(resolve => {
        setTimeout(() => {
            if (policy === 'all') resolve(data);
            else resolve(data.filter(item => item.policy === policy));
        }, 500);
    });
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        policy: 'all',
        data: [],
        keywords: '',
        value: [],
    } as Props;

    private __test: any;

    private originData: DataItem[] | null = null;

    componentDidMount() {
        this.fetch();
    }

    @bind
    fetch() {
        mockApi(this.state.policy!).then(data => {
            if (this.$unmounted) return;
            this.originData = data;
            this.filter();
        });
    }

    @bind
    filter() {
        const keywords = this.state.keywords;
        const data = keywords ? 
            this.originData!.filter(data => {
                return data.name.includes(keywords);
            }) :
            this.originData!;
        this.setState({data: data});
    }

    private $unmounted: boolean = false;

    componentWillUnmount() {
        this.$unmounted = true;
    }

    setState(state: any, cb?: () => void) {
        if ('policy' in state) {
            super.setState(state, this.fetch);
        } else if ('keywords' in state) {
            super.setState(state, this.filter);
        } else {
            super.setState(state, cb);
        }
    }

    render() {
        return (
            <div>
                <Transfer data={this.state.data}
                    slotFilter={(type) => {
                        return <>
                            {type === 'left' ?
                                <Input size="small"
                                    slotPrepend={<>
                                        <Select value={this.state.policy} onChangeValue={policy => this.setState({policy})} width="100" size="small">
                                            <Option value="all">全部策略</Option>
                                            <Option value="system">系统策略</Option>
                                            <Option value="common">通用策略</Option>
                                        </Select>
                                    </>}
                                    placeholder="请输入"
                                    clearable
                                    value={this.state.keywords}
                                    onChangeValue={keywords => this.setState({keywords})}
                                >
                                </Input> :
                                undefined
                            }
                        </>
                    }}
                    slotLabel={([data, index, type]) => {
                        return <>
                            <div>
                                <div>
                                    {data.name}
                                    {data.policy === 'system' ?
                                        <Tag type="warning" size="mini">系统策略</Tag> :
                                        undefined
                                    }
                                </div>
                                <p>{data.members}人 / {data.desc}</p>
                            </div>
                        </>
                    }}
                    filterable
                    keyName="name"
                    value={this.state.value}
                    onChangeValue={value => this.setState({value})}
                    ref={i => this.__test = i}
                >
                </Transfer>
                <p>You selected: {JSON.stringify(this.state.value)}</p>
            </div>
        )
    }
}

