                                    <DropdownItem onSelect={this.removeNode.bind(this, data, node, index)}>Remove</DropdownItem>
                                </DropdownMenu>
                            </Dropdown>
                        </>
                    }}
                    data={this.state.data}
                    expandedKeys={this.state.expandedKeys}
                    onChangeExpandedKeys={expandedKeys => this.setState({expandedKeys})}
                >
                </Tree>
