import React from 'react';
import {TreeSelect} from '@king-design/react';
import {bind, TreeSelectProps, TreeNode} from '@king-design/react';

interface Props {
    data: NonNullable<TreeSelectProps['data']>
}

export default class Demo extends React.Component<{}, Props> {
    public state = {
        data: [
            {
                label: 'parent',
                key: '1', 
                children: [
                    {label: 'first child', children: [], key: '1.1'},
                    {label: 'last child', children: [], loaded: true, key: '1.2'},
                ],
            },
        ],
    };

    @bind
    loadData(node: TreeNode<string>) {
        return new Promise<void>(resolve => {
            setTimeout(() => {
                node.data.children = [
                    {label: `child ${node.key}.1`, children: [], key: `${node.key}.1`},
                    {label: `child ${node.key}.2`, key: `${node.key}.2`},
                ];
                this.setState({data: [...this.state.data]});

                resolve();
            }, 1000);
        });
    }

    render() {
        return (
            <TreeSelect data={this.state.data} 
                load={this.loadData}
            />
        )
    }
}

